'use client';

import { useState } from 'react';
import Link from 'next/link';
import { ArrowLeft, Video, Image, Sparkles, Upload, Wand2 } from 'lucide-react';
import { MODELS, ASPECT_RATIOS, estimateCost } from '@/lib/gemini-client';

type CreationMode = 'video' | 'image';
type VideoModel = typeof MODELS.VEO_2 | typeof MODELS.VEO_3 | typeof MODELS.VEO_3_FAST;
type ImageModel = typeof MODELS.IMAGEN_4 | typeof MODELS.GEMINI_FLASH_IMAGE;

export default function CreatePage() {
  const [mode, setMode] = useState<CreationMode>('video');
  const [prompt, setPrompt] = useState('');
  const [negativePrompt, setNegativePrompt] = useState('');
  const [videoModel, setVideoModel] = useState<VideoModel>(MODELS.VEO_3);
  const [imageModel, setImageModel] = useState<ImageModel>(MODELS.IMAGEN_4);
  const [aspectRatio, setAspectRatio] = useState<string>(ASPECT_RATIOS['16:9']);
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const currentModel = mode === 'video' ? videoModel : imageModel;
  const estimatedCost = estimateCost(currentModel, 5);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setResult(null);

    try {
      const endpoint = mode === 'video' ? '/api/veo/generate' : '/api/imagen/generate';
      
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          prompt,
          model: currentModel,
          aspectRatio,
          negativePrompt: negativePrompt || undefined,
        }),
      });

      const data = await response.json();

      if (data.success) {
        setResult(data.operationName || data.imageUrl);
      } else {
        alert(`Error: ${data.error || 'Generation failed'}`);
      }
    } catch (error) {
      console.error('Generation error:', error);
      alert('Failed to generate content. Please try again.');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <main className="min-h-screen">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        {/* Header */}
        <div className="mb-8">
          <Link 
            href="/"
            className="inline-flex items-center gap-2 text-gray-400 hover:text-white transition-colors mb-4"
          >
            <ArrowLeft className="w-4 h-4" />
            Back to Home
          </Link>
          
          <h1 className="text-4xl font-bold bg-gradient-to-r from-cyan-400 via-purple-400 to-orange-400 bg-clip-text text-transparent mb-2">
            Create with AI
          </h1>
          <p className="text-gray-400">
            Generate stunning videos and images using Google's most advanced AI models
          </p>
        </div>

        {/* Mode Selector */}
        <div className="flex gap-4 mb-8">
          <button
            onClick={() => setMode('video')}
            className={`flex-1 p-6 rounded-xl border-2 transition-all ${
              mode === 'video'
                ? 'border-cyan-500 bg-cyan-500/10'
                : 'border-white/10 bg-white/5 hover:border-white/20'
            }`}
          >
            <Video className={`w-8 h-8 mb-2 ${mode === 'video' ? 'text-cyan-400' : 'text-gray-400'}`} />
            <div className="font-semibold text-white">Video Generation</div>
            <div className="text-sm text-gray-400">Create videos with Veo 3</div>
          </button>

          <button
            onClick={() => setMode('image')}
            className={`flex-1 p-6 rounded-xl border-2 transition-all ${
              mode === 'image'
                ? 'border-purple-500 bg-purple-500/10'
                : 'border-white/10 bg-white/5 hover:border-white/20'
            }`}
          >
            <Image className={`w-8 h-8 mb-2 ${mode === 'image' ? 'text-purple-400' : 'text-gray-400'}`} />
            <div className="font-semibold text-white">Image Generation</div>
            <div className="text-sm text-gray-400">Create images with Imagen 4</div>
          </button>
        </div>

        <div className="grid lg:grid-cols-2 gap-8">
          {/* Left Column - Controls */}
          <div className="space-y-6">
            {/* Model Selector */}
            <div className="p-6 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
              <label className="block text-sm font-medium text-gray-300 mb-3">
                Model
              </label>
              {mode === 'video' ? (
                <select
                  value={videoModel}
                  onChange={(e) => setVideoModel(e.target.value as VideoModel)}
                  className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/20 text-white focus:outline-none focus:border-cyan-500"
                >
                  <option value={MODELS.VEO_3}>Veo 3 (Best Quality)</option>
                  <option value={MODELS.VEO_2}>Veo 2 (Balanced)</option>
                  <option value={MODELS.VEO_3_FAST}>Veo 3 Fast (Fastest)</option>
                </select>
              ) : (
                <select
                  value={imageModel}
                  onChange={(e) => setImageModel(e.target.value as ImageModel)}
                  className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/20 text-white focus:outline-none focus:border-purple-500"
                >
                  <option value={MODELS.IMAGEN_4}>Imagen 4 (Best Quality)</option>
                  <option value={MODELS.GEMINI_FLASH_IMAGE}>Gemini 2.5 Flash Image (Fast)</option>
                </select>
              )}
            </div>

            {/* Prompt */}
            <div className="p-6 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
              <label className="block text-sm font-medium text-gray-300 mb-3">
                Prompt
              </label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={mode === 'video' 
                  ? "Describe the video you want to create... (e.g., 'A cinematic shot of Buenos Aires at sunset, with electric buses moving silently through the streets')"
                  : "Describe the image you want to create... (e.g., 'A futuristic city with green acoustic barriers and peaceful parks')"}
                className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/20 text-white placeholder-gray-500 focus:outline-none focus:border-cyan-500 min-h-[120px]"
              />
            </div>

            {/* Negative Prompt */}
            <div className="p-6 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
              <label className="block text-sm font-medium text-gray-300 mb-3">
                Negative Prompt (Optional)
              </label>
              <input
                type="text"
                value={negativePrompt}
                onChange={(e) => setNegativePrompt(e.target.value)}
                placeholder="What to avoid... (e.g., 'blurry, low quality, distorted')"
                className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/20 text-white placeholder-gray-500 focus:outline-none focus:border-cyan-500"
              />
            </div>

            {/* Aspect Ratio */}
            <div className="p-6 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
              <label className="block text-sm font-medium text-gray-300 mb-3">
                Aspect Ratio
              </label>
              <div className="grid grid-cols-4 gap-2">
                {Object.entries(ASPECT_RATIOS).map(([key, value]) => (
                  <button
                    key={key}
                    onClick={() => setAspectRatio(value)}
                    className={`px-4 py-2 rounded-lg border-2 transition-all ${
                      aspectRatio === value
                        ? 'border-cyan-500 bg-cyan-500/10 text-cyan-400'
                        : 'border-white/10 bg-white/5 text-gray-400 hover:border-white/20'
                    }`}
                  >
                    {key}
                  </button>
                ))}
              </div>
            </div>

            {/* Cost Estimate */}
            <div className="p-6 rounded-xl bg-gradient-to-r from-cyan-500/10 to-purple-500/10 border border-cyan-500/30">
              <div className="flex items-center justify-between">
                <div>
                  <div className="text-sm text-gray-300 mb-1">Estimated Cost</div>
                  <div className="text-2xl font-bold text-white">${estimatedCost.toFixed(2)}</div>
                </div>
                <Sparkles className="w-8 h-8 text-cyan-400" />
              </div>
            </div>

            {/* Generate Button */}
            <button
              onClick={handleGenerate}
              disabled={!prompt || isGenerating}
              className="w-full px-8 py-4 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-lg font-semibold text-white hover:shadow-lg hover:shadow-purple-500/50 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
            >
              {isGenerating ? (
                <>
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  Generating...
                </>
              ) : (
                <>
                  <Wand2 className="w-5 h-5" />
                  Generate {mode === 'video' ? 'Video' : 'Image'}
                </>
              )}
            </button>
          </div>

          {/* Right Column - Preview */}
          <div className="p-8 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
            <h3 className="text-lg font-semibold text-white mb-4">Preview</h3>
            
            {result ? (
              <div className="space-y-4">
                <div className="p-4 rounded-lg bg-green-500/10 border border-green-500/30 text-green-400">
                  ✓ Generation started successfully!
                </div>
                <div className="text-sm text-gray-400">
                  <strong>Operation ID:</strong> {result}
                </div>
                <p className="text-sm text-gray-400">
                  Your {mode} is being generated. This may take a few minutes. 
                  Check the gallery for your completed {mode}.
                </p>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-64 text-gray-500">
                <Upload className="w-16 h-16 mb-4 opacity-50" />
                <p>Your generated {mode} will appear here</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </main>
  );
}
