import { GoogleGenerativeAI } from '@google/generative-ai';

if (!process.env.GEMINI_API_KEY) {
  throw new Error('GEMINI_API_KEY environment variable is not set');
}

export const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);

// Model configurations
export const MODELS = {
  // Video models
  VEO_2: 'veo-2',
  VEO_3: 'veo-3',
  VEO_3_FAST: 'veo-3-fast',
  
  // Image models
  IMAGEN_4: 'imagen-4',
  GEMINI_FLASH_IMAGE: 'gemini-2.5-flash-image',
  
  // Text models
  GEMINI_FLASH: 'gemini-2.5-flash',
} as const;

export type ModelType = typeof MODELS[keyof typeof MODELS];

// Aspect ratios
export const ASPECT_RATIOS = {
  '16:9': '16:9',
  '9:16': '9:16',
  '1:1': '1:1',
  '4:3': '4:3',
} as const;

export type AspectRatio = typeof ASPECT_RATIOS[keyof typeof ASPECT_RATIOS];

// Resolutions
export const RESOLUTIONS = {
  '720p': '720p',
  '1080p': '1080p',
} as const;

export type Resolution = typeof RESOLUTIONS[keyof typeof RESOLUTIONS];

// Video generation request
export interface VideoGenerationRequest {
  prompt: string;
  model: ModelType;
  aspectRatio: AspectRatio;
  resolution?: Resolution;
  referenceImages?: string[]; // Base64 encoded images
  negativePrompt?: string;
}

// Image generation request
export interface ImageGenerationRequest {
  prompt: string;
  model: ModelType;
  aspectRatio?: AspectRatio;
  negativePrompt?: string;
  referenceImages?: string[]; // For editing/composition
}

// Operation status
export interface OperationStatus {
  name: string;
  done: boolean;
  metadata?: {
    createTime: string;
    updateTime: string;
  };
  response?: {
    video?: {
      uri: string;
    };
    image?: {
      uri: string;
    };
  };
  error?: {
    code: number;
    message: string;
  };
}

// Helper function to convert base64 to blob
export function base64ToBlob(base64: string, contentType: string = 'image/jpeg'): Blob {
  const byteCharacters = atob(base64.split(',')[1] || base64);
  const byteNumbers = new Array(byteCharacters.length);
  
  for (let i = 0; i < byteCharacters.length; i++) {
    byteNumbers[i] = byteCharacters.charCodeAt(i);
  }
  
  const byteArray = new Uint8Array(byteNumbers);
  return new Blob([byteArray], { type: contentType });
}

// Helper function to estimate cost (approximate)
export function estimateCost(model: ModelType, duration: number = 5): number {
  const costs: Record<string, number> = {
    [MODELS.VEO_2]: 0.10,
    [MODELS.VEO_3]: 0.15,
    [MODELS.VEO_3_FAST]: 0.05,
    [MODELS.IMAGEN_4]: 0.04,
    [MODELS.GEMINI_FLASH_IMAGE]: 0.02,
  };
  
  const baseCost = costs[model] || 0.10;
  
  // Video models charge per second
  if (model.includes('veo')) {
    return baseCost * duration;
  }
  
  // Image models charge per image
  return baseCost;
}

// Helper function to format operation name
export function formatOperationName(operationName: string): string {
  return operationName.replace('operations/', '');
}

// Helper function to check if operation is complete
export function isOperationComplete(operation: OperationStatus): boolean {
  return operation.done === true;
}

// Helper function to get video/image URL from operation
export function getMediaUrl(operation: OperationStatus): string | null {
  if (!operation.response) return null;
  
  if (operation.response.video?.uri) {
    return operation.response.video.uri;
  }
  
  if (operation.response.image?.uri) {
    return operation.response.image.uri;
  }
  
  return null;
}
